insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'A sits in the middle. B is at the left end. D sits between B and A. E sits to the right of A. Who sits at the right end?', 'A middle में बैठा है। B left end पर है। D, B और A के बीच है। E, A के right में है। Right end पर कौन है?', 'Final order is B - D - A - E - C; right end is C. Therefore, answer = C.', 'Linear puzzle clues should be converted into a final row before answering. End positions and immediate-neighbour clues are common traps. Final answer is C.', 'Final order B - D - A - E - C है; right end C है। अतः answer = C।', 'Linear puzzle clues को final row में convert करें। End positions और immediate-neighbour clues common traps हैं। Final answer C है।', 'EASY', array['reasoning','puzzle','seating-arrangement']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
