insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'P sits in the middle. Q is at the left end. S sits between Q and P. T sits to the right of P. Who sits at the right end?', 'P middle में बैठा है। Q left end पर है। S, Q और P के बीच है। T, P के right में है। Right end पर कौन है?', 'Final order is Q - S - P - T - R; right end is R. Therefore, answer = R.', 'Linear puzzle clues should be converted into a final row before answering. End positions and immediate-neighbour clues are common traps. Final answer is R.', 'Final order Q - S - P - T - R है; right end R है। अतः answer = R।', 'Linear puzzle clues को final row में convert करें। End positions और immediate-neighbour clues common traps हैं। Final answer R है।', 'EASY', array['reasoning','puzzle','seating-arrangement']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
