insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'A map shows a point 6 km east and 8 km north from the start. What is the shortest distance from the start?', 'Map में एक point start से 6 km east और 8 km north है। Start से shortest distance क्या है?', 'Shortest distance = sqrt(6^2 + 8^2) = 10 km. Therefore, answer = 10 km.', 'Map distance between perpendicular directions is a Pythagoras problem. The direct distance is the hypotenuse, not the sum of the legs. Final answer is 10 km.', 'Shortest distance = sqrt(6^2 + 8^2) = 10 km। अतः answer = 10 km।', 'Perpendicular directions का map distance Pythagoras problem है। Direct distance hypotenuse होता है, legs का sum नहीं। Final answer 10 km है।', 'MEDIUM', array['reasoning','maps','direction-sense']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '14 km', '14 km', false, 'Added path components and reported route length, not straight-line distance.', 'Components add करके route length दे दी, straight-line distance नहीं।');
